const input = $input.first().json;
console.log('[WF2 v7] Processing form submission');

let data = null;
let parseSource = 'unknown';

if (input.body?.clarificationId) {
  data = input.body;
  parseSource = 'input.body (FLAT)';
} else if (input.body?.data?.clarificationId) {
  data = input.body.data;
  parseSource = 'input.body.data';
} else if (input.body?.body?.data?.clarificationId) {
  data = input.body.body.data;
  parseSource = 'input.body.body.data';
} else if (input.body?.body?.clarificationId) {
  data = input.body.body;
  parseSource = 'input.body.body';
} else if (input.clarificationId) {
  data = input;
  parseSource = 'input (root)';
}

if (!data) {
  return { json: { isValid: false, isTest: false, errors: ['Could not parse payload'], parseSource: 'FAILED' } };
}

const isTest = data._isTest === true || (data.clarificationId && data.clarificationId.startsWith('TEST-'));
const clarificationId = data.clarificationId || '';
const nguonChiDao = data.nguonChiDao || '';
const ngayNhanChiDao = data.ngayNhanChiDao || '';
const noiDungGoc = data.noiDungGoc || '';
const dauMoiT1 = data.dauMoiT1 || '';
const t2NhiemVu = data.t2NhiemVu || '';
const t3ChiTieu = data.t3ChiTieu || '';
const t4ThoiHan = data.t4ThoiHan || '';
const ghiChu = data.ghiChu || '';
const xacNhan = data.xacNhan === true || data.xacNhan === 'true' || (typeof data.xacNhan === 'string' && data.xacNhan.includes('xác nhận'));
const respondentEmail = data.respondentEmail || 'anonymous';

const errors = [];
if (!clarificationId || clarificationId.length < 10) errors.push('Thiếu Mã Clarification');
if (!t2NhiemVu || t2NhiemVu.length < 3) errors.push('Thiếu T2');
if (!t3ChiTieu || t3ChiTieu.length < 3) errors.push('Thiếu T3');
if (!t4ThoiHan) errors.push('Thiếu T4');
if (!xacNhan) errors.push('Chưa xác nhận');

const isValid = errors.length === 0;
let missingTags = [];
if (!dauMoiT1) missingTags.push('Thiếu T1-TÊN');
if (!t2NhiemVu) missingTags.push('Thiếu T2-NHIỆM VỤ');
if (!t3ChiTieu) missingTags.push('Thiếu T3-CHỈ TIÊU');
if (!t4ThoiHan) missingTags.push('Thiếu T4-THỜI HẠN');
const has4T = missingTags.length === 0;

let hrSearchKeyword = '';
if (dauMoiT1) {
  hrSearchKeyword = dauMoiT1.replace(/^(HR|Nhóm|Ms\.?|Mr\.?)\s*/i, '').trim();
  const words = hrSearchKeyword.split(/\s+/);
  if (words.length > 1) hrSearchKeyword = words[words.length - 1];
}

return { json: { isValid, isTest, errors, parseSource, clarificationId, nguonChiDao, ngayNhanChiDao, noiDungGoc, dauMoiT1, t2NhiemVu, t3ChiTieu, t4ThoiHan, ghiChu, xacNhan, respondentEmail, has4T, missingTags, hrSearchKeyword, today: new Date().toISOString().split('T')[0] } };

// Get form data from IF: Có T1? node
const formData = $('IF: Có T1?').first().json;
const searchResult = $input.first().json;

let hrId = '', hrEmail = '', hrName = '', hrFound = false;
try {
  const results = searchResult.results || [];
  if (results.length > 0) {
    const hr = results[0];
    hrId = hr.id;
    hrEmail = hr.properties?.['Email']?.email || '';
    hrName = hr.properties?.['Họ và Tên']?.title?.[0]?.plain_text || '';
    hrFound = true;
    console.log('[WF2 v7] HR Found:', hrName, hrEmail);
  }
} catch (e) { console.log('HR error:', e.message); }

// CRITICAL: Pass ALL form data forward
return { json: { ...formData, hrId, hrEmail, hrName, hrFound } };

// No HR search - pass through ALL form data
const formData = $('IF: Có T1?').first().json;
return { json: { ...formData, hrId: '', hrEmail: '', hrName: '', hrFound: false } };

// Merge node - ensure we have all data regardless of HR path
let data;
try {
  data = $('📝 Extract HR Info').first().json;
  console.log('[WF2 v7] Data from HR path');
} catch (e) {
  try {
    data = $('📄 No HR Search').first().json;
    console.log('[WF2 v7] Data from No HR path');
  } catch (e2) {
    console.log('[WF2 v7] ERROR: Could not get data from either path');
    return { json: { error: 'No data available' } };
  }
}

console.log('[WF2 v7] Merged data:', JSON.stringify(data).substring(0, 200));
return { json: data };

